import ast
from collections import defaultdict
from pathlib import Path
root = Path("cohort_projections")
modules = {".".join(p.with_suffix("").parts): p for p in root.rglob("*.py")}
graph = defaultdict(set)
for mod, p in modules.items():
    tree = ast.parse(p.read_text(encoding="utf-8", errors="ignore"))
    for node in ast.walk(tree):
        if isinstance(node, ast.Import):
            for alias in node.names:
                name = alias.name
                if name.startswith("cohort_projections") and name in modules:
                    graph[mod].add(name)
        elif isinstance(node, ast.ImportFrom):
            if node.level and node.module is not None:
                parts = mod.split(".")[:-node.level]
                target = ".".join(parts + node.module.split("."))
            elif node.level and node.module is None:
                parts = mod.split(".")[:-node.level]
                target = ".".join(parts)
            else:
                target = node.module or ""
            if target.startswith("cohort_projections") and target in modules:
                graph[mod].add(target)

cycles = []
temp, perm = set(), set()
def visit(node, stack):
    if node in perm:
        return
    if node in temp:
        idx = stack.index(node)
        cycles.append(stack[idx:] + [node])
        return
    temp.add(node)
    stack.append(node)
    for nxt in graph.get(node, set()):
        visit(nxt, stack)
    stack.pop()
    temp.remove(node)
    perm.add(node)

for m in modules:
    if m not in perm:
        visit(m, [])
print(f"MODULE_COUNT={len(modules)}")
print(f"CYCLE_COUNT={len(cycles)}")
if len(cycles) == 0:
    print("ASSERTION=PASS")
else:
    print("ASSERTION=FAIL")
    raise SystemExit(1)
